options.css:
/* Пересвет конфигуратор — компактные стили без Bootstrap (только нужные утилиты + bstreeview + prs) */
/* Палитра IoTerra — см. src/configurator_grafana/ioterra_100.png (петроль + терракота) */
@charset "UTF-8";

:root {
  --ioterra-teal: #2c707f;
  --ioterra-teal-dark: #235a66;
  --ioterra-teal-light: #e6f2f4;
  --ioterra-rust: #a34a28;
  --ioterra-rust-dark: #863c20;
  --prs-primary: var(--ioterra-teal);
  --prs-secondary: #5a6d72;
  --prs-danger: var(--ioterra-rust);
  --prs-border: #dee2e6;
  --prs-muted: #5c6569;
  --prs-body: #212529;
  --prs-bg: #fff;
  --prs-radius: 0.375rem;
}

*, *::before, *::after {
  box-sizing: border-box;
}

/* —— сетка —— */
.row {
  display: flex;
  flex-wrap: wrap;
  margin-right: -0.375rem;
  margin-left: -0.375rem;
}
.row > * {
  padding-right: 0.375rem;
  padding-left: 0.375rem;
}
.col { flex: 1 0 0%; max-width: 100%; }
.col-1 { flex: 0 0 8.333333%; max-width: 8.333333%; }
.col-2 { flex: 0 0 16.666667%; max-width: 16.666667%; }
.col-4 { flex: 0 0 33.333333%; max-width: 33.333333%; }

/* —— display / flex —— */
.d-flex { display: flex !important; }
.flex-grow-1 { flex: 1 1 auto !important; }
.flex-shrink-0 { flex-shrink: 0 !important; }
.overflow-auto { overflow: auto !important; }
.border-bottom { border-bottom: 1px solid var(--prs-border) !important; }
.d-none { display: none !important; }
.flex-column { flex-direction: column !important; }
.flex-grow-0 { flex-grow: 0 !important; }
.flex-shrink-0 { flex-shrink: 0 !important; }
.justify-content-start { justify-content: flex-start !important; }
.justify-content-center { justify-content: center !important; }
.align-items-start { align-items: flex-start !important; }
.align-items-center { align-items: center !important; }
.align-items-stretch { align-items: stretch !important; }
.space-between { justify-content: space-between; }

/* —— отступы —— */
.m-1 { margin: 0.25rem !important; }
.m-2 { margin: 0.5rem !important; }
.mt-1 { margin-top: 0.25rem !important; }
.mt-2 { margin-top: 0.5rem !important; }
.mt-3 { margin-top: 1rem !important; }
.mb-0 { margin-bottom: 0 !important; }
.mb-1 { margin-bottom: 0.25rem !important; }
.mb-2 { margin-bottom: 0.5rem !important; }
.me-1 { margin-right: 0.25rem !important; }
.me-2 { margin-right: 0.5rem !important; }
.mx-1 { margin-left: 0.25rem !important; margin-right: 0.25rem !important; }
.my-2 { margin-top: 0.5rem !important; margin-bottom: 0.5rem !important; }
.p-0 { padding: 0 !important; }
.p-2 { padding: 0.5rem !important; }
.px-1 { padding-left: 0.25rem !important; padding-right: 0.25rem !important; }
.px-3 { padding-left: 1rem !important; padding-right: 1rem !important; }
.py-2 { padding-top: 0.5rem !important; padding-bottom: 0.5rem !important; }
.py-3 { padding-top: 1rem !important; padding-bottom: 1rem !important; }

@media (min-width: 576px) {
  .mt-sm-2 { margin-top: 0.5rem !important; }
}

/* —— типографика —— */
.text-start { text-align: start !important; }
.text-left { text-align: left !important; }
.text-muted { color: var(--prs-muted) !important; }
.fw-semibold { font-weight: 600 !important; }
.fs-4 { font-size: 1.5rem !important; }
.bg-light { background-color: #f8f9fa !important; }
.border { border: 1px solid var(--prs-border) !important; }
.rounded { border-radius: var(--prs-radius) !important; }
.disabled, :disabled { opacity: 0.65; pointer-events: none; }

/* —— кнопки —— */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.2rem;
  font-weight: 500;
  line-height: 1.5;
  text-align: center;
  cursor: pointer;
  user-select: none;
  border: 1px solid transparent;
  padding: 0.375rem 0.75rem;
  font-size: 1rem;
  border-radius: var(--prs-radius);
  background-color: transparent;
  transition: color 0.15s, background-color 0.15s, border-color 0.15s;
}
.btn-sm {
  padding: 0.25rem 0.5rem;
  font-size: 0.875rem;
  border-radius: 0.25rem;
}
.btn-primary {
  color: #fff;
  background-color: var(--ioterra-teal);
  border-color: var(--ioterra-teal-dark);
  box-shadow: 0 2px 4px rgba(44, 112, 127, 0.35);
}
.btn-primary:hover { filter: brightness(1.05); }
.btn-secondary {
  color: #fff;
  background-color: #5c636a;
  border-color: #565e64;
}
.btn-secondary:hover:not(:disabled) {
  background-color: #495057;
  border-color: #41464b;
}
.btn-outline-primary {
  color: var(--ioterra-teal-dark);
  border-color: var(--ioterra-teal);
  background-color: var(--ioterra-teal-light);
  font-weight: 600;
}
.btn-outline-primary:hover {
  color: #fff;
  background-color: var(--ioterra-teal);
  border-color: var(--ioterra-teal-dark);
}
.btn-outline-secondary {
  color: #343a40;
  border-color: #6c757d;
  background-color: #eef1f4;
  font-weight: 600;
}
.btn-outline-secondary:hover {
  color: #fff;
  background-color: #495057;
  border-color: #3d4449;
}
.btn-danger {
  color: #fff;
  background-color: var(--ioterra-rust);
  border-color: var(--ioterra-rust-dark);
}
.btn-danger:hover { filter: brightness(1.06); }

.btn-close {
  box-sizing: content-box;
  width: 1em;
  height: 1em;
  padding: 0.25em;
  color: #000;
  background: transparent url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 16 16' fill='%23000'%3e%3cpath d='M.293.293a1 1 0 011.414 0L8 6.586 14.293.293a1 1 0 111.414 1.414L9.414 8l6.293 6.293a1 1 0 01-1.414 1.414L8 9.414l-6.293 6.293a1 1 0 01-1.414-1.414L6.586 8 .293 1.707a1 1 0 010-1.414z'/%3e%3c/svg%3e") center/1em auto no-repeat;
  border: 0;
  border-radius: 0.25rem;
  opacity: 0.5;
  cursor: pointer;
}
.btn-close:hover { opacity: 1; }

/* —— поля —— */
.form-control, .form-select {
  display: block;
  width: 100%;
  padding: 0.375rem 0.75rem;
  font-size: 0.9375rem;
  font-weight: 400;
  line-height: 1.5;
  color: var(--prs-body);
  background-color: var(--prs-bg);
  border: 1px solid #ced4da;
  border-radius: var(--prs-radius);
  appearance: none;
  transition: border-color 0.15s ease, box-shadow 0.15s ease;
}
.form-control-sm {
  padding: 0.25rem 0.5rem;
  font-size: 0.875rem;
  border-radius: 0.25rem;
}
.form-control:focus, .form-select:focus {
  border-color: #5a9daa;
  outline: 0;
  box-shadow: 0 0 0 0.2rem rgba(44, 112, 127, 0.22);
}
.form-select {
  background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 16 16'%3e%3cpath fill='none' stroke='%23343a40' stroke-linecap='round' stroke-linejoin='round' stroke-width='2' d='M2 5l6 6 6-6'/%3e%3c/svg%3e");
  background-repeat: no-repeat;
  background-position: right 0.6rem center;
  background-size: 12px;
  padding-right: 2rem;
}

.form-check {
  display: block;
  min-height: 1.5rem;
  padding-left: 1.6em;
  margin-bottom: 0.25rem;
}
.form-check-input {
  float: left;
  width: 1em;
  height: 1em;
  margin-top: 0.2em;
  margin-left: -1.6em;
  vertical-align: top;
  border: 1px solid #adb5bd;
  appearance: none;
  background-color: #fff;
  border-radius: 0.25em;
}
.form-check-input:checked {
  background-color: var(--ioterra-teal);
  border-color: var(--ioterra-teal-dark);
  background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 20 20'%3e%3cpath fill='none' stroke='%23fff' stroke-linecap='round' stroke-linejoin='round' stroke-width='3' d='M6 10l3 3 6-6'/%3e%3c/svg%3e");
  background-size: 100%;
}
.form-check-label {
  cursor: pointer;
}
.form-switch .form-check-input {
  width: 2em;
  border-radius: 2em;
  background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='-4 -4 8 8'%3e%3ccircle r='3' fill='%23fff'/%3e%3c/svg%3e");
  background-position: left center;
  background-repeat: no-repeat;
  background-size: contain;
  transition: background-position 0.15s ease-in-out;
}
.form-switch .form-check-input:checked {
  background-position: right center;
}

.input-group {
  display: flex;
  align-items: stretch;
  width: 100%;
}
.input-group-text {
  display: flex;
  align-items: center;
  padding: 0.375rem 0.75rem;
  font-size: 0.875rem;
  color: var(--prs-muted);
  background-color: #e9ecef;
  border: 1px solid #ced4da;
  border-radius: var(--prs-radius);
}
.input-group > .form-control,
.input-group > .form-select {
  position: relative;
  flex: 1 1 auto;
  min-width: 0;
}
.input-group > :not(:first-child) {
  margin-left: -1px;
  border-top-left-radius: 0;
  border-bottom-left-radius: 0;
}
.input-group > :not(:last-child) {
  border-top-right-radius: 0;
  border-bottom-right-radius: 0;
}

/* —— навигация / вкладки —— */
.nav {
  display: flex;
  flex-wrap: wrap;
  padding-left: 0;
  margin-bottom: 0;
  list-style: none;
}
.nav-pills .nav-link {
  display: block;
  padding: 0.5rem 0.75rem;
  border-radius: var(--prs-radius);
  color: var(--prs-primary);
  text-decoration: none;
  cursor: pointer;
}
.nav-pills .nav-link:hover { background-color: var(--ioterra-teal-light); }
.nav-pills .nav-link.active {
  color: #fff;
  background-color: var(--ioterra-teal);
  border: 1px solid var(--ioterra-teal-dark);
}
.tab-content > .tab-pane { display: none; }
.tab-content > .tab-pane.active,
.tab-content > .tab-pane.show { display: block; }
.fade { transition: opacity 0.15s linear; }
.fade:not(.show) { opacity: 0; }

/* collapse (bstreeview / дерево) */
.collapse:not(.show) { display: none; }
.collapsing { height: 0; overflow: hidden; transition: height 0.2s ease; }

/* —— таблица —— */
.table {
  width: 100%;
  margin-bottom: 0.5rem;
  border-collapse: collapse;
  font-size: 0.875rem;
}
.table th, .table td {
  padding: 0.35rem 0.5rem;
  border-bottom: 1px solid var(--prs-border);
  vertical-align: middle;
}
.table-sm th, .table-sm td { padding: 0.2rem 0.35rem; }

/* —— алерты —— */
.alert {
  position: relative;
  padding: 0.65rem 2.25rem 0.65rem 0.75rem;
  margin-bottom: 0.5rem;
  border: 1px solid transparent;
  border-radius: var(--prs-radius);
  font-size: 0.875rem;
}
.alert-dismissible { padding-right: 2.5rem; }
.alert-primary { color: #084298; background: #cfe2ff; border-color: #b6d4fe; }
.alert-secondary { color: #41464b; background: #e2e3e5; border-color: #d3d6d8; }
.alert-success { color: #0f5132; background: #d1e7dd; border-color: #badbcc; }
.alert-danger { color: #842029; background: #f8d7da; border-color: #f5c2c7; }
.alert-warning { color: #664d03; background: #fff3cd; border-color: #ffecb5; }
.alert-info { color: #055160; background: #cff4fc; border-color: #b6effb; }

/* list-group (bstreeview) */
.list-group {
  padding-left: 0;
  margin: 0;
  list-style: none;
}
.list-group-item {
  position: relative;
  padding: 0.35rem 0.65rem;
  border: 1px solid rgba(0,0,0,.125);
  border-bottom-width: 0;
}
.list-group-item:last-child { border-bottom-width: 1px; }

/*
 bstreeview.css v1.2.0 — Apache 2.0 — https://github.com/chniter/bstreeview
*/
.bstreeview {
  position: relative;
  display: flex;
  flex-direction: column;
  min-width: 0;
  word-wrap: break-word;
  background-clip: border-box;
  border: 1px solid rgba(0,0,0,.125);
  border-radius: 5px;
  padding: 0.25rem 0.6rem;
  overflow: hidden;
  width: 100%;
}
.bstreeview .list-group { margin-bottom: 0; }
.bstreeview .list-group-item {
  border-radius: 0;
  border-width: 0;
  /* иначе остаётся padding-left/right: 0.65rem от .list-group-item — «Объекты» уезжали вправо */
  padding-top: 0.2rem;
  padding-bottom: 0.2rem;
  padding-left: 0;
  padding-right: 0.35rem;
  cursor: pointer;
}
.bstreeview .list-group-item:hover { background-color: rgba(44, 112, 127, 0.14); }
.bstreeview > .list-group-item:first-child { border-top-width: 0; }
/*
 * Вложенные уровни: padding на group (без #tree — надёжнее в shadow DOM Grafana).
 * Родительская строка — снаружи group, дети — внутри → дети обязаны быть правее.
 */
.main-container .bstreeview .list-group[role="group"] {
  padding-left: 0.5rem !important;
  padding-right: 0 !important;
  margin: 0 !important;
  box-sizing: border-box !important;
  border-left: none;
  box-shadow: inset 1px 0 0 rgba(0, 0, 0, 0.05);
}
/* Вложенные группы (привязанные теги под хранилищем) — дополнительный отступ */
.main-container .bstreeview .list-group[role="group"] .list-group[role="group"] {
  padding-left: 1.5rem !important;
}
.bstreeview .state-icon {
  margin-right: 8px;
  min-width: 1.15em;
  font-size: 1.05rem;
  line-height: 1;
  text-align: center;
}
.bstreeview .item-icon {
  margin-right: 6px;
  font-size: 1.15rem;
  line-height: 1;
  min-width: 1.2em;
}
/* Одна и та же ширина шеврона на всех уровнях — иначе при клике/раскрытии строка «прыгает» (корень был 0.82em, дети 1em). */
.bstreeview .list-group-item[role="treeitem"] > .state-icon,
.bstreeview .list-group-item[role="treeitem"] > [data-prs-chevron-placeholder] {
  flex: 0 0 0.82em;
  width: 0.82em;
  min-width: 0.82em !important;
  max-width: 0.82em;
  box-sizing: border-box;
  margin-right: 2px;
  overflow: hidden;
  text-align: center;
  font-size: 0.95rem;
}
.bstreeview .list-group-item[role="treeitem"] > .item-icon {
  flex: 0 0 1em;
  width: 1em;
  min-width: 1em !important;
  max-width: 1em;
  box-sizing: border-box;
  margin-right: 3px;
  overflow: hidden;
}

/* Резерв под шеврон: невидимый <i data-prs-chevron-placeholder> в JS (те же классы, что у шеврона) */

/* Иконки на кнопках — крупнее и контрастнее (псевдо-FA в тени Grafana) */
.main-container .btn i.fa-solid {
  font-size: 1.2rem !important;
  line-height: 1 !important;
  min-width: 1.35em !important;
  font-weight: 800 !important;
  text-shadow: 0 1px 3px rgba(0, 0, 0, 0.35);
  filter: contrast(1.15);
  vertical-align: middle;
}
.main-container .btn.btn-sm i.fa-solid {
  font-size: 1.1rem !important;
  min-width: 1.25em !important;
}
.main-container .btn.btn-icon {
  gap: 0.2rem;
  padding-left: 0.4rem;
  padding-right: 0.55rem;
}
.main-container .btn.btn-icon .icon i.fa-solid {
  font-size: 1.25rem !important;
}
/* второй значок «плюс» рядом с иконкой типа */
.main-container .btn.btn-icon > i.fa-solid:last-child {
  font-size: 1.35rem !important;
  font-weight: 900 !important;
  margin-left: 0.08rem;
}

/* контраст панели: иконки-кнопки, disabled */
.btn-icon.btn-sm {
  min-width: 2.55rem;
  min-height: 2.15rem;
}
.btn .fa-solid,
.btn .icon {
  opacity: 1;
}
.btn.disabled,
.btn:disabled {
  opacity: 0.72;
  pointer-events: none;
}

/* Перебить глобальные стили Grafana — палитра IoTerra */
.main-container button.btn-primary,
.main-container .btn.btn-primary {
  background-color: #2c707f !important;
  border-color: #235a66 !important;
  color: #fff !important;
  box-shadow: 0 2px 5px rgba(44, 112, 127, 0.4) !important;
}
.main-container .btn.btn-danger {
  background-color: #a34a28 !important;
  border-color: #863c20 !important;
  color: #fff !important;
}
.main-container .btn-outline-primary {
  color: #1a4d58 !important;
  border: 2px solid #2c707f !important;
  background-color: #e6f2f4 !important;
  font-weight: 600 !important;
}
.main-container .btn-outline-primary:hover {
  color: #fff !important;
  background-color: #2c707f !important;
  border-color: #235a66 !important;
}
.main-container .btn-outline-secondary {
  color: #2a2f33 !important;
  border: 2px solid #5a6d72 !important;
  background-color: #eef1f2 !important;
  font-weight: 600 !important;
}
.main-container .btn-outline-secondary:hover {
  color: #fff !important;
  background-color: #3d5a62 !important;
  border-color: #2c707f !important;
}
.main-container .btn-secondary {
  background-color: #3d5a62 !important;
  border-color: #2f4a52 !important;
  color: #fff !important;
}
.main-container .btn .icon {
  background: rgba(0, 0, 0, 0.22) !important;
}

/* --- сплиттер: дерево | свойства --- */
.main-container.prs-split-root {
  display: flex;
  flex-direction: row;
  align-items: stretch;
  width: 100%;
  min-height: min(88vh, 920px);
  gap: 0;
}
.prs-split-pane.prs-split-left {
  flex: 0 0 34%;
  min-width: 220px;
  max-width: 62%;
  display: flex;
  flex-direction: column;
  min-height: 0;
}
.prs-split-pane.prs-split-right {
  flex: 1 1 auto;
  min-width: 200px;
  min-height: 0;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}
.prs-splitter {
  flex: 0 0 8px;
  cursor: col-resize;
  background: linear-gradient(90deg, rgba(44,112,127,.1), rgba(44,112,127,.32) 48%, rgba(44,112,127,.1));
  border-left: 1px solid rgba(44,112,127,.22);
  border-right: 1px solid rgba(44,112,127,.22);
  z-index: 3;
}
.prs-splitter:hover {
  background: linear-gradient(90deg, rgba(163,74,40,.12), rgba(44,112,127,.4) 50%, rgba(163,74,40,.12));
}
.prs-tree-scroll {
  flex: 1 1 auto;
  min-height: 120px;
  overflow-y: auto;
}
/* Правая колонка */
#prs-split-right {
  align-items: stretch;
}
.prs-right-placeholder {
  flex: 1 1 auto;
  min-height: 5rem;
  max-width: 100%;
}

/* компактные кнопки в строках дерева */
.bstreeview .list-group-item[role="treeitem"] {
  position: relative;
  padding-left: 0 !important;
  padding-right: 0.35rem !important;
  display: flex;
  flex-wrap: nowrap;
  overflow: hidden;
  min-width: 0;
  align-items: center;
  gap: 0 0.25rem;
}
/* длинные подписи сжимаются; иконки и бейдж — фиксированной ширины */
.bstreeview .list-group-item[role="treeitem"] > * {
  min-width: 0;
}
.bstreeview .list-group-item[role="treeitem"] > .state-icon,
.bstreeview .list-group-item[role="treeitem"] > [data-prs-chevron-placeholder],
.bstreeview .list-group-item[role="treeitem"] > .item-icon,
.bstreeview .list-group-item[role="treeitem"] > .prs-default-badge {
  min-width: auto;
  flex-shrink: 0;
}
.bstreeview .list-group-item[role="treeitem"] > .prs-node-actions {
  min-width: auto;
  flex-shrink: 0;
}
.bstreeview .list-group-item[role="treeitem"]:focus,
.bstreeview .list-group-item[role="treeitem"]:focus-visible {
  outline: none !important;
  box-shadow: none !important;
}
.prs-pre-wrap {
  white-space: pre-wrap;
  word-break: break-word;
}
/* Корневые строки: класс задаётся в JS, жёсткий сброс отступов чтобы не съезжало после открытия/закрытия */
.prs-tree-root-item {
  position: relative;
  padding-left: 1.4rem !important;
  margin-left: 0 !important;
  margin-right: 0 !important;
  padding-right: 5rem !important;
  box-sizing: border-box !important;
}
.prs-tree-root-item > .state-icon {
  position: absolute;
  left: 0;
  margin-right: 0;
}
#tree.bstreeview > .list-group-item[role="treeitem"] {
  padding-left: 0 !important;
  margin-left: 0 !important;
}
.prs-default-badge {
  display: inline-block;
  flex-shrink: 0;
  margin-left: 0.35rem;
  width: 0.55rem;
  height: 0.55rem;
  padding: 0;
