    width: 1%;
}
.input-group > .form-select {
    display: block;
    padding: 0.375rem 2.25rem 0.375rem 0.75rem;
    line-height: 1.5;
    min-height: calc(1.5em + 0.75rem + 2px);
    border: 1px solid #ced4da;
    border-radius: 0.25rem;
}

/* —— Конфигуратор Grafana: единый стиль и новые виджеты —— */
.main-container {
    gap: 8px;
    align-items: stretch;
}
.element-holder {
    background: rgba(0, 0, 0, 0.02);
    border: 1px solid #dee2e6;
    border-radius: 12px;
    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.04);
}

/* левая колонка конфигуратора: дерево + хранилища — прокрутка внутри панели Grafana */
.element-holder.col-4 {
    max-height: min(92vh, 960px);
    overflow-y: auto;
    min-height: 0;
}
.sub-element {
    border-radius: 8px;
    background: rgba(255, 255, 255, 0.6);
}
.prs-card {
    border: 1px solid #dee2e6;
    border-radius: 10px;
    background: #fff;
    padding: 10px 12px;
}
.prs-card-title {
    font-size: 0.95rem;
    font-weight: 600;
    margin: 0 0 8px 0;
    color: #343a40;
    display: flex;
    align-items: center;
    gap: 8px;
}
.prs-picker-list {
    max-height: 200px;
    overflow-y: auto;
    border: 1px solid #ced4da;
    border-radius: 8px;
    background: #fff;
    font-size: 0.875rem;
}
.prs-picker-row {
    padding: 6px 10px;
    display: flex;
    align-items: center;
    gap: 8px;
    cursor: pointer;
    border-bottom: 1px solid #f1f3f5;
}
.prs-picker-row:last-child {
    border-bottom: none;
}
.prs-picker-row:hover {
    background: #e6f2f4;
}
.prs-picker-row.prs-hidden {
    display: none;
}
.prs-chips {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
    min-height: 28px;
}
.prs-chip {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border-radius: 999px;
    background: #e9ecef;
    font-size: 0.75rem;
    max-width: 100%;
}
.prs-chip button {
    border: none;
    background: none;
    padding: 0 2px;
    cursor: pointer;
    color: #6c757d;
    line-height: 1;
}
.prs-chip button:hover {
    color: #dc3545;
}
.prs-drop-zone {
    min-height: 36px;
    border: 2px dashed #adb5bd;
    border-radius: 8px;
    padding: 6px 8px;
    margin-top: 6px;
    font-size: 0.8rem;
    color: #6c757d;
    transition: background 0.15s, border-color 0.15s;
}
.prs-drop-zone.prs-drag-over {
    background: #e6f2f4;
    border-color: #2c707f;
    color: #235a66;
}
.prs-ds-row {
    border: 1px solid #e9ecef;
    border-radius: 8px;
    padding: 8px;
    margin-bottom: 8px;
    background: #fafbfc;
}
.prs-ds-row .prs-ds-meta {
    font-size: 0.75rem;
    color: #6c757d;
    word-break: break-all;
}
.prs-mono {
    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
    font-size: 0.75rem;
}
#attributes-form .row {
    margin-bottom: 4px;
}
#attributes-form h3#div-nodeName {
    font-size: 1.35rem;
    margin: 0;
}


/* пиктограммы без внешних шрифтов — чуть крупнее базово */
i.fa-solid { font-style: normal; display: inline-block; width: 1.15em; text-align: center; vertical-align: -0.08em; font-size: 1.05em; line-height: 1; font-weight: 700; }
.fa-solid.fa-object-group::before { content: "\229E"; }
.fa-solid.fa-object-ungroup::before { content: "\229E"; }
/* \2316 — прицел (crosshair), не тег; метка U+1F3F7 */
.fa-solid.fa-tag::before { content: "\1F3F7"; }
.fa-solid.fa-tags::before { content: "\1F3F7"; }
.fa-solid.fa-link::before { content: "\221E"; }
.fa-solid.fa-clock::before { content: "\231A"; }
.fa-solid.fa-bell::before { content: "\237E"; }
.fa-solid.fa-file-code::before { content: "\2325"; }
.fa-solid.fa-plus::before { content: "+"; font-weight: 900; }
.fa-solid.fa-trash-can::before { content: "\232B"; }
.fa-solid.fa-xmark::before { content: "\00D7"; font-weight: 900; }
.fa-solid.fa-download::before { content: "\2913"; }
.fa-solid.fa-circle-exclamation::before { content: "!"; font-weight: 900; font-size: 0.85em; }
.fa-solid.fa-circle-info::before { content: "i"; font-weight: 900; font-style: italic; font-size: 0.75em; }
.fa-solid.fa-minus::before { content: "\2212"; font-weight: 900; }
.fa-solid.fa-rotate::before { content: "\21BB"; }
.fa-solid.fa-database::before { content: "\228C"; }
.prs-brand { font-weight: 700; color: #2c707f; margin-right: 0.35em; }

/* Автопривязка тегов */
.prs-border-subtle { border-bottom: 1px solid var(--prs-border, #dee2e6); }

/* Автопривязка: нативная галочка + flex (кастомный .form-check-input часто без видимой галочки в HTML-панели Grafana) */
.prs-auto-link-wrap .form-check.prs-auto-link-check {
  display: flex;
  align-items: flex-start;
  gap: 0.5rem;
  padding-left: 0;
  margin-bottom: 0;
}
.prs-auto-link-wrap .prs-auto-link-check .form-check-input {
  float: none;
  margin-left: 0;
  margin-top: 0.15rem;
  width: 1.15rem;
  height: 1.15rem;
  flex-shrink: 0;
  appearance: auto;
  -webkit-appearance: checkbox;
  accent-color: var(--ioterra-teal);
}
.prs-auto-link-wrap .prs-auto-link-check .form-check-input:checked {
  background-color: transparent !important;
  background-image: none !important;
}
.prs-auto-link-wrap .prs-auto-link-check .form-check-label {
  padding-top: 0.05rem;
  line-height: 1.35;
}



/* Дерево: цветом — привязан к БД / нет */

/* Флажок автопривязки: нативная галка (не form-check-input с appearance:none) */
.prs-auto-link-label {
  display: flex;
  align-items: flex-start;
  gap: 0.5rem;
  cursor: pointer;
  font-size: 0.8125rem;
  line-height: 1.35;
  margin: 0;
  user-select: none;
}
.prs-auto-link-label input[type="checkbox"] {
  appearance: auto;
  -webkit-appearance: checkbox;
  width: 1.15rem;
  height: 1.15rem;
  margin: 0.15rem 0 0 0;
  flex-shrink: 0;
  accent-color: var(--ioterra-teal);
  cursor: pointer;
}
.prs-auto-link-text {
  flex: 1;
  min-width: 0;
}
/* Вертикальная направляющая дерева — одна линия на уровень вложенности */
/* Подсказка привязки к БД — тонкая полоска, не конфликтует с линией группы */
/* Привязка к БД: без inset-полосок — они дублировали border группы и давали «толстые» разноцветные линии */
#tree .list-group-item.prsTag.prs-tag-tree-linked,
#tree .list-group-item.prsTag.prs-tag-tree-unlinked {
  border-left: none !important;
  padding-left: 0.5rem;
  box-shadow: none !important;
}
#tree .list-group-item.prsTag.prs-tag-tree-linked > .item-icon {
  color: var(--ioterra-teal, #2c707f) !important;
}
#tree .list-group-item.prsTag.prs-tag-tree-unlinked > .item-icon {
  color: var(--ioterra-rust, #a34a28) !important;
}
/* Панель v2 привязки — под полями формы */
.prs-linked-tag-panel {
  max-width: 100%;
}
/* Вкладки правой панели */
/* Вкладки формы: закладки в ряд — активная с белым фоном и верхней полосой бренда */
#prs-form-tabs {
  display: flex;
  flex-wrap: nowrap;
  align-items: flex-end;
  gap: 0;
  margin: 0;
  padding: 0;
  border: none;
  border-bottom: 1px solid #d0d5d8;
  background: transparent;
  border-radius: 6px 6px 0 0;
  box-shadow: none;
  position: relative;
  z-index: 2;
}
#prs-form-tabs .nav-item {
  margin: 0;
  list-style: none;
}
#prs-form-tabs .nav-link {
  position: relative;
  margin: 0 0 0 -1px;
  padding: 0.55rem 1.1rem;
  font-size: 0.875rem;
  font-weight: 500;
  letter-spacing: 0.01em;
  color: #6c757d;
  background: #f2f2f2;
  border: 1px solid #d0d5d8 !important;
  border-bottom-color: #d0d5d8;
  border-radius: 0;
  transition: background 0.15s ease, color 0.15s ease;
  cursor: pointer;
}
#prs-form-tabs .nav-item:first-child .nav-link {
  margin-left: 0;
}
#prs-form-tabs .nav-link:focus-visible {
  outline: 2px solid rgba(44, 112, 127, 0.45);
  outline-offset: 1px;
  z-index: 3;
}
#prs-form-tabs .nav-link:hover:not(.active) {
  background: #e8e8e8;
  color: #495057;
}
#prs-form-tabs .nav-link.active {
  margin-bottom: -1px;
  padding: 0.5rem 1.1rem 0.58rem;
  font-weight: 700;
  color: #212529 !important;
  background: #fff !important;
  border: 1px solid #d0d5d8 !important;
  border-top: 4px solid var(--ioterra-teal, #2c707f);
  border-bottom: 1px solid #fff;
  z-index: 2;
}
#prs-form-normal-wrap.prs-form-tab-stack {
  display: flex;
  flex-direction: column;
  align-items: stretch;
  width: 100%;
  min-width: 0;
}
#prs-form-tab-content {
  width: 100%;
  min-width: 0;
  position: relative;
  z-index: 1;
  margin-top: 0;
  padding: 0.75rem 0.35rem 0.2rem;
  background: #fff;
  border: 1px solid #d0d5d8;
  border-top: none;
  border-radius: 0 0 var(--prs-radius) var(--prs-radius);
}
#prs-form-tab-content .tab-pane {
  min-height: 0;
}

/* —— Правая панель: без «толстых» двойных линий у input-group — одна рамка на строку —— */
#attributes-form #prs-form-normal-wrap .input-group,
#attributes-form .tab-content .input-group {
  border: 1px solid rgba(0, 0, 0, 0.1);
  border-radius: var(--prs-radius);
  overflow: hidden;
  background: #fff;
}
#attributes-form #prs-form-normal-wrap .input-group > :not(:first-child),
#attributes-form .tab-content .input-group > :not(:first-child) {
  margin-left: 0 !important;
}
#attributes-form #prs-form-normal-wrap .input-group > .input-group-text,
#attributes-form .tab-content .input-group > .input-group-text {
  border: none !important;
  border-radius: 0 !important;
  box-shadow: inset -1px 0 0 rgba(0, 0, 0, 0.07);
}
#attributes-form #prs-form-normal-wrap .input-group > .form-control,
#attributes-form #prs-form-normal-wrap .input-group > .form-select,
#attributes-form .tab-content .input-group > .form-control,
#attributes-form .tab-content .input-group > .form-select {
  border: none !important;
  border-radius: 0 !important;
}
#attributes-form #prs-form-normal-wrap .input-group > textarea.form-control,
#attributes-form .tab-content .input-group > textarea.form-control {
  border: none !important;
  border-radius: 0 !important;
}
#attributes-form #prs-form-normal-wrap .input-group > .form-control:focus,
#attributes-form #prs-form-normal-wrap .input-group > .form-select:focus,
#attributes-form .tab-content .input-group > .form-control:focus,
#attributes-form .tab-content .input-group > .form-select:focus {
  outline: none;
  box-shadow: inset 0 0 0 1px rgba(44, 112, 127, 0.45) !important;
  z-index: 1;
  position: relative;
}

/* Дерево: кнопки в ряд без «двойной» обводки между соседними */
.prs-node-actions .prs-node-btn + .prs-node-btn {
  margin-left: -1px;
}
.prs-node-actions .prs-node-btn {
  position: relative;
  z-index: 0;
}
.prs-node-actions .prs-node-btn:hover {
  z-index: 1;
}
.bstreeview .list-group-item[role="treeitem"] > .prs-node-actions {
  padding-left: 0.25rem;
}


/* Изменённые поля: рамка поверх «безбордерного» input-group */
#attributes-form #prs-form-normal-wrap .input-group > .form-control.value-changed,
#attributes-form #prs-form-normal-wrap .input-group > .form-select.value-changed,
#attributes-form .tab-content .input-group > .form-control.value-changed,
#attributes-form .tab-content .input-group > .form-select.value-changed,
#attributes-form .input-group > textarea.form-control.value-changed {
  box-shadow: inset 0 0 0 2px rgba(44, 112, 127, 0.95) !important;
  background-color: rgba(230, 242, 244, 0.55) !important;
  z-index: 2;
}
/* Подпись узла в дереве */
.prs-tree-label {
  min-width: 0;
  flex: 1 1 auto;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Кнопки записи: сильнее контраст idle vs есть изменения */
#attributes-form #but-save.disabled,
#attributes-form #but-reset.disabled {
  opacity: 0.38 !important;
  filter: grayscale(0.35);
  box-shadow: none !important;
}
#attributes-form #but-save:not(.disabled),
#attributes-form #but-reset:not(.disabled) {
  opacity: 1 !important;
  filter: none;
}

/* Редактор операций привязки тега v2 */
.prs-linked-ops-editor .prs-op-card {
  border: 1px solid var(--prs-border, #dee2e6);
  border-radius: var(--prs-radius, 0.375rem);
  padding: 0.65rem 0.75rem;
  margin-bottom: 0.75rem;
  background: #fafbfb;
}
.prs-linked-raw-json summary {
  cursor: pointer;
}

.prs-linked-ops-editor .prs-op-fields-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 1rem;
  align-items: flex-end;
  margin-bottom: 0.5rem;
}
.prs-linked-ops-editor .prs-op-field {
  flex: 1 1 10rem;
  min-width: 8rem;
}
.prs-linked-ops-editor .prs-op-field-wide {
  flex: 2 1 16rem;
  min-width: 12rem;
}

/* Подвкладки «Запрос на чтение / запись» у данных тега */
.prs-tag-data-tabs {
  display: flex;
  flex-wrap: nowrap;
  align-items: flex-end;
  gap: 0;
  margin: 0;
  padding: 0;
  border: none;
  border-bottom: 1px solid #d0d5d8;
  background: transparent;
  border-radius: 6px 6px 0 0;
}
.prs-tag-data-tabs .nav-item { margin: 0; list-style: none; }
.prs-tag-data-tabs .nav-link {
  position: relative;
  margin: 0 0 0 -1px;
  padding: 0.4rem 0.75rem;
  font-size: 0.8125rem;
  font-weight: 500;
  color: #6c757d;
  background: #f2f2f2;
  border: 1px solid #d0d5d8 !important;
  border-radius: 0;
  cursor: pointer;
}
.prs-tag-data-tabs .nav-item:first-child .nav-link { margin-left: 0; }
.prs-tag-data-tabs .nav-link.active {
  margin-bottom: -1px;
  font-weight: 700;
  color: #212529 !important;
  background: #fff !important;
  border: 1px solid #d0d5d8 !important;
  border-top: 3px solid var(--ioterra-teal, #2c707f);
  border-bottom: 1px solid #fff;
  z-index: 2;
}
.prs-tag-data-tab-content {
  border: 1px solid #d0d5d8;
  border-top: none;
  background: #fff;
  border-radius: 0 0 var(--prs-radius) var(--prs-radius);
}
/* Чекбоксы как у автопривязки — видимая галка, цвет палитры */
.prs-tag-data-toggle-label {
  display: flex;
  align-items: flex-start;
  gap: 0.5rem;
  cursor: pointer;
  font-size: 0.8125rem;
  line-height: 1.35;
  margin: 0;
  user-select: none;
  color: var(--prs-body, #212529);
}
.prs-tag-data-toggle-input {
  appearance: auto;
  -webkit-appearance: checkbox;
  width: 1.15rem;
  height: 1.15rem;
  margin: 0.12rem 0 0 0;
  flex-shrink: 0;
  accent-color: var(--ioterra-teal, #2c707f);
  cursor: pointer;
}
/* Таблица данных тега */
.prs-tag-data-table-wrap { overflow-x: auto; }
table.prs-tag-data-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.8125rem;
  border: 1px solid #c5ccd1;
}
table.prs-tag-data-table thead th {
  background: linear-gradient(180deg, #eef4f5 0%, #dfe8ea 100%);
  color: #2a3f44;
  font-weight: 600;
  padding: 0.45rem 0.5rem;
  border-bottom: 2px solid #b8c4c8;
  border-right: 1px solid #c5ccd1;
  text-align: left;
}
table.prs-tag-data-table thead th:last-child { border-right: none; }
table.prs-tag-data-table tbody td {
  padding: 0.35rem 0.5rem;
  border-bottom: 1px solid #dee2e6;
  border-right: 1px solid #e9ecef;
  vertical-align: top;
}
table.prs-tag-data-table tbody td:last-child { border-right: none; }
table.prs-tag-data-table tbody tr:nth-child(even) { background: #fafcfc; }

/* Чекбокс «Привязка тега к хранилищу» — как переключатели в «Запрос на чтение» (галка, цвет палитры) */
.prs-auto-link-wrap .prs-auto-link-check .form-check-input {
  appearance: auto;
  -webkit-appearance: checkbox;
  width: 1.15rem;
  height: 1.15rem;
  accent-color: var(--ioterra-teal, #2c707f);
  flex-shrink: 0;
}
.prs-auto-link-wrap .prs-auto-link-check .form-check-input:checked {
  background-color: transparent !important;
  background-image: none !important;
}
table.prs-tag-data-table { table-layout: fixed; }
table.prs-tag-data-table thead th { position: relative; }
.prs-tag-data-col-resizer {
  position: absolute;
  top: 0;
  right: 0;
  width: 6px;
  height: 100%;
  cursor: col-resize;
  user-select: none;
}
.prs-tag-data-col-resizer:hover { background: rgba(44, 112, 127, 0.2); }

.prs-tag-get-flags .prs-op-fields-row { display: flex; flex-wrap: wrap; gap: 0.5rem 1rem; align-items: flex-end; margin-bottom: 0.5rem; }
.prs-tag-get-flags .prs-op-field { flex: 1 1 8rem; min-width: 6rem; }

.prs-flags-one-row {
  display: flex;
  flex-wrap: wrap;
  align-items: stretch;
  gap: 0 0.25rem;
}
.prs-flags-one-row .prs-flag-unit {
  flex: 0 0 auto;
  width: auto;
  min-width: 0;
}
.prs-flags-one-row .input-group-sm .prs-flag-label {
  padding: 0.2rem 0.4rem;
  font-size: 0.75rem;
  white-space: nowrap;
}
.prs-flags-one-row .prs-flag-unit .form-control,
.prs-flags-one-row .prs-flag-unit .prs-flag-value {
  min-width: 2.5rem;
  max-width: 6rem;
  padding: 0.2rem 0.35rem;
  font-size: 0.75rem;
}
.prs-flags-one-row .prs-flag-unit-value .form-control { max-width: 8rem; }
.prs-flags-one-row .prs-flag-unit .prs-tag-data-toggle-input { margin: 0; }

/* Поиск тегов/расписаний (метод) — как в prs-inkscape-grafana */
.prs-method-search-results {
  max-height: 14rem;
  overflow-y: auto;
  border: 1px solid var(--prs-border, #dee2e6);
  border-radius: var(--prs-radius, 0.375rem);
  background: var(--prs-bg, #fff);
}
.prs-method-search-row {
  display: flex;
  align-items: stretch;
  gap: 0.35rem;
  padding: 0.4rem 0.5rem;
  border-bottom: 1px solid var(--prs-border, #dee2e6);
}
.prs-method-search-row:last-child { border-bottom: none; }
.prs-method-search-row:hover { background: var(--ioterra-teal-light, #e6f2f4); }
.prs-anchor-btn {
  flex: 0 0 auto;
  align-self: flex-start;
  border: none;
  background: transparent;
  color: var(--prs-primary, #2c707f);
  padding: 0.2rem 0.4rem;
  border-radius: 0.25rem;
}
.prs-anchor-btn:hover:not(:disabled) { background: rgba(44, 112, 127, 0.12); }
.prs-anchor-btn:disabled { opacity: 0.35; cursor: not-allowed; }
.prs-method-search-main { flex: 1; min-width: 0; }
.prs-method-search-path { font-size: 0.8125rem; font-weight: 600; line-height: 1.25; }
.prs-method-search-meta { font-size: 0.7rem; color: var(--prs-muted, #5c6569); font-family: ui-monospace, monospace; margin-top: 0.15rem; word-break: break-all; }
.prs-method-initiators-wrap .nav-tabs .nav-link { padding: 0.35rem 0.65rem; font-size: 0.8125rem; }
.prs-param-tag-wrap { min-width: 0; }

/* Вкладки «Теги / Расписания» у метода — как #prs-form-tabs */
#prs-method-init-tabs {
  display: flex;
  flex-wrap: nowrap;
  align-items: stretch;
  gap: 0;
  margin: 0 0 0.35rem 0;
  padding: 0;
  border: none;
  border-bottom: 1px solid #d0d5d8;
  background: transparent;
  border-radius: 6px 6px 0 0;
  list-style: none;
}
#prs-method-init-tabs .nav-item {
  margin: 0;
  list-style: none;
  display: flex;
  align-items: stretch;
}
#prs-method-init-tabs .nav-link {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  margin: 0 0 0 -1px;
  min-height: 2rem;
  height: 2rem;
  padding: 0 1.1rem;
  font-size: 0.875rem;
  font-weight: 500;
  letter-spacing: 0.01em;
  color: #6c757d;
  background: #f2f2f2;
  border: 1px solid #d0d5d8 !important;
  border-bottom-color: #d0d5d8;
  border-radius: 0;
  cursor: pointer;
  outline: none !important;
  box-shadow: none !important;
}
#prs-method-init-tabs .nav-item:first-child .nav-link { margin-left: 0; }
#prs-method-init-tabs .nav-link:focus,
#prs-method-init-tabs .nav-link:focus-visible {
  outline: none !important;
  box-shadow: none !important;
}
#prs-method-init-tabs .nav-link:hover:not(.active) {
  background: #e8e8e8;
  color: #495057;
}
#prs-method-init-tabs .nav-link.active {
  margin-bottom: -1px;
  min-height: 2rem;
  height: 2rem;
  padding: 0 1.1rem;
  font-weight: 700;
  color: #212529 !important;
  background: #fff !important;
  border: 1px solid #d0d5d8 !important;
  border-top: 4px solid var(--ioterra-teal, #2c707f);
  border-bottom: 1px solid #fff;
  z-index: 2;
  outline: none !important;
  box-shadow: none !important;
}
.prs-meth-search-trigger {
  border: none !important;
  box-shadow: none !important;
  text-decoration: none !important;
  color: var(--prs-muted, #6c757d) !important;
  line-height: 1.2;
  font-size: 1rem;
  min-width: 2rem;
}
.prs-meth-search-trigger:hover,
.prs-meth-search-trigger:focus {
  color: var(--prs-primary, #2c707f) !important;
  background: transparent !important;
}
.prs-param-tag-pick-label .prs-pick-path {
  font-weight: 600;
  color: #343a40;
  font-size: 0.78rem;
  line-height: 1.2;
  margin-bottom: 2px;
  word-break: break-word;
}
.prs-param-tag-pick-label .prs-pick-meta {
  font-size: 0.72rem;
  color: var(--prs-muted, #6c757d);
  word-break: break-all;
}
.prs-param-tag-pick-label .prs-pick-saved-note {
  font-size: 0.68rem;
  color: var(--prs-muted, #6c757d);
  font-style: italic;
  margin-bottom: 2px;
}
.prs-anchor-glyph {
  display: inline-block;
  font-size: 1.05rem;
  line-height: 1;
  vertical-align: middle;
}

