prsInitSplitter = function () {
  var root = __prsConfiguratorHtmlNode.querySelector(".prs-split-root");
  var left = __prsConfiguratorHtmlNode.getElementById("prs-split-left");
  var spl = __prsConfiguratorHtmlNode.getElementById("prs-splitter");
  if (!root || !left || !spl) return;
  try {
    var w = localStorage.getItem("prsSplitLeftPct");
    if (w) left.style.flex = "0 0 " + parseFloat(w, 10) + "%";
  } catch (e1) {}
  spl.addEventListener("mousedown", function (e) {
    e.preventDefault();
    var startX = e.clientX;
    var startW = left.getBoundingClientRect().width;
    var total = root.getBoundingClientRect().width;
    function move(ev) {
      var dx = ev.clientX - startX;
      var nw = startW + dx;
      var pct = Math.min(62, Math.max(20, (nw / total) * 100));
      left.style.flex = "0 0 " + pct + "%";
    }
    function up() {
      document.removeEventListener("mousemove", move);
      document.removeEventListener("mouseup", up);
      try {
        localStorage.setItem("prsSplitLeftPct", String((left.getBoundingClientRect().width / root.getBoundingClientRect().width) * 100));
      } catch (e2) {}
    }
    document.addEventListener("mousemove", move);
    document.addEventListener("mouseup", up);
  });
};

