  var a = o.attributes && typeof o.attributes === "object" ? o.attributes : {};
  var cfg = prsParseJsonMaybe(a.prsJsonConfigString);
  if (typeof cfg !== "object" || cfg === null) cfg = {};
  var jta = cfg.JSONata;
  if (jta != null && typeof jta !== "string") jta = JSON.stringify(jta);
  a.cn = prsFirstStr(a.cn) || "";
  a.prsActive = a.prsActive !== false && a.prsActive !== "FALSE";
  a.prsJsonConfigString = { JSONata: jta != null ? String(jta) : "" };
  o.attributes = a;
  return o;
}

function prsNormalizeOperation(op) {
  var o = op && typeof op === "object" ? op : {};
  var a = o.attributes && typeof o.attributes === "object" ? o.attributes : {};
  var cfg = prsParseJsonMaybe(a.prsJsonConfigString);
  if (typeof cfg !== "object" || cfg === null) cfg = {};
  a.cn = prsFirstStr(a.cn) || "";
  a.prsActive = a.prsActive !== false && a.prsActive !== "FALSE";
  var etc = parseInt(String(a.prsEntityTypeCode != null ? a.prsEntityTypeCode : 0), 10);
  a.prsEntityTypeCode = isFinite(etc) ? etc : 0;
  a.prsJsonConfigString = {
    query: cfg.query != null ? String(cfg.query) : "",
    timeoutMs: cfg.timeoutMs != null ? Number(cfg.timeoutMs) : 5000,
    maxRows: cfg.maxRows != null ? Number(cfg.maxRows) : 10000,
    version: cfg.version != null ? Number(cfg.version) : 1
  };
  var params = Array.isArray(o.parameters) ? o.parameters : [];
  o.parameters = params.map(prsNormalizeParameter);
  o.attributes = a;
  return o;
}

