prsSaveDsLinkedTagOps = function () {
  var root = __prsConfiguratorHtmlNode;
  var panel = root.getElementById("prs-ds-linked-tag-panel");
  var ta = root.getElementById("textarea-prs-ds-linked-tag-ops");
  if (!panel) return;
  if (panel.dataset.entityClass === "prsDsLinkedAlert" && !ta) return;
  var dsId = panel.dataset.dsId;
  var entId = panel.dataset.entityId;
  var isAlert = panel.dataset.entityClass === "prsDsLinkedAlert";
  if (!dsId || !entId) return;
  var parsed;
  if (!isAlert && prsLinkedTagEntryState) {
    parsed = prsLinkedTagPayloadFromState();
  } else {
    try { parsed = JSON.parse((ta && ta.value) || "{}"); } catch (e1) {
      showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", "Некорректный JSON", false);
      return;
    }
  }
  if (isAlert) {
    showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", "Для тревог используйте привязку через дерево или API v1 PUT (linkedAlerts).", false);
    return;
  }
  var v2url = window.location.protocol + "//" + window.location.hostname + "/v2/dataStorages/?id=" + encodeURIComponent(dsId) + "&getLinkedTags=true";
  fetch(v2url, { headers: { "Content-type": "application/json" } }).then(function (r) { return r.json(); }).then(function (data) {
    var one = data && data.data && data.data[0];
    var lt = one && one.linkedTags ? one.linkedTags.slice() : [];
    if (!parsed.tagId) parsed.tagId = entId;
    var idx = -1;
    for (var i = 0; i < lt.length; i++) {
      if (String(lt[i].tagId) === String(parsed.tagId)) { idx = i; break; }
    }
    if (idx >= 0) lt[idx] = parsed;
    else lt.push(parsed);
    return fetch(window.location.protocol + "//" + window.location.hostname + "/v2/dataStorages/", {
      method: "PUT",
      body: JSON.stringify({ id: dsId, linkedTags: lt }),
      headers: new Headers({ "Content-Type": "application/json" })
    });
  }).then(function (response) {
    if (!response || response.status !== 202) {
      showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", "Ошибка записи v2", false);
      return;
    }
    showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateDataAlert", "linkedTags обновлён.", true);
  }).catch(function () {
    showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", "Ошибка записи v2", false);
  });
};

