};

prsTreeRowFromEvent = function (event) {
  var t = event.target;
  if (t && t.nodeType === 3) t = t.parentElement;
  if (!t || typeof t.closest !== "function") return null;
  return t.closest('[role="treeitem"]');
};

getFocus = (event) => {
  event.stopPropagation();

  const prev = __prsConfiguratorHtmlNode.querySelectorAll(".currentNode");
  [...prev].forEach((n) => { n.classList.remove("currentNode"); });
  const row = prsTreeRowFromEvent(event);
  if (row) {
    row.classList.add("currentNode");
    const rid = row.id;
    const ocl = row.getAttribute("objectClass");
    if (ocl && !topNodesIds.includes(rid)) {
      removeClassOnElements("value-changed");
      setAttributesVisibility(row);
      setAddButtonsVisibility(row);
      fillForm(row);
    }
  }
  if (typeof prsSyncRightPlaceholder === "function") prsSyncRightPlaceholder();
};

sortList = (group) => {
  var new_group = group.cloneNode(false);
  // Add all lis to an array
  var groupItems = [];
  for (var i = 0; i < group.childNodes.length; i++) {
    if (group.childNodes[i].getAttribute("role") === 'treeitem')
      groupItems.push(group.childNodes[i]);
  }
  function prsIndexOf(el) {
    var v = el.getAttribute("data-prs-index");
    if (v === null || v === "") return Infinity;
    var n = parseInt(v, 10);
    return isNaN(n) ? Infinity : n;
  }
  groupItems.sort((a, b) => {
    var ia = prsIndexOf(a), ib = prsIndexOf(b);
    if (ia !== ib) return ia - ib;
    if ((a.getAttribute("objectClass") == "prsObject") && (b.getAttribute("objectClass") == "prsTag")) return -1;
    if ((a.getAttribute("objectClass") == "prsTag") && (b.getAttribute("objectClass") == "prsObject")) return 1;
    return (a.textContent || "") < (b.textContent || "") ? -1 : 1;
  });

  for (var i = 0; i < groupItems.length; i++) {
    new_group.appendChild(groupItems[i]);
    //dataBsTargetId = groupItems[i].getAttribute("data-bs-target").substring(1);
    //itemGroup = __prsConfiguratorHtmlNode.getElementById(dataBsTargetId);
    //if (itemGroup) new_group
  }

  if (group.parentNode !== null) {
    group.parentNode.replaceChild(new_group, group);
  };
};

addNode = (parentElement, node, top = false) => {
  // добавление узла в иерархию
  // parentElement - родительский элемент
  // node - {
  //  id: "...",
  //  text: "...",
  //  icon: "....",
  //  objectClass: "...",
  // }
  // top - добавлять в начало списка

  // атрибут data-bs-target у узла всегда создаётся, но вот
  // элемента, на который он указывает, может и не быть
  parentGroupId = parentElement.getAttribute("data-bs-target").substring(1);
  parentGroup = __prsConfiguratorHtmlNode.getElementById(parentGroupId);
  if (!parentGroup) {
    parentGroup = document.createElement("div");
    parentGroup.setAttribute("role", "group");
    parentGroup.setAttribute("class", "list-group collapse show");
    parentGroup.setAttribute("id", parentGroupId);

    parentElement.parentNode.insertBefore(parentGroup, parentElement.nextSibling);

    var ph = parentElement.querySelector("[data-prs-chevron-placeholder]");
    var haveChev = parentElement.querySelector("[data-prs-tree-chevron]");
    parentElement.querySelectorAll(":scope > .state-icon").forEach(function (el) {
      if (el === ph || el === haveChev) return;
      if (!el.hasAttribute("data-prs-tree-chevron") && !el.hasAttribute("data-prs-chevron-placeholder")) el.remove();
    });
    var chev = parentElement.querySelector("[data-prs-tree-chevron]");
    if (ph && !chev) {
      ph.removeAttribute("data-prs-chevron-placeholder");
      ph.setAttribute("data-prs-tree-chevron", "1");
      ph.style.visibility = "";
      ph.className = "state-icon " + options.expandIcon;
    } else if (!chev) {
      chev = document.createElement("i");
      chev.setAttribute("data-prs-tree-chevron", "1");
      parentElement.insertBefore(chev, parentElement.firstChild);
      chev.className = "state-icon " + options.expandIcon;
    } else {
      chev.className = "state-icon " + options.expandIcon;
    }
    if (parentElement.parentNode && parentElement.parentNode.id === "tree") { parentElement.removeAttribute("style"); if (ph) ph.remove(); }
}

  parentAreaLevel = Number(parentElement.getAttribute("aria-level"));
  if (!isFinite(parentAreaLevel) || parentAreaLevel < 1) parentAreaLevel = 1;

  itemDiv = document.createElement("div");
  itemDiv.setAttribute("id", node.id);
  itemDiv.setAttribute("role", "treeitem");
  itemDiv.setAttribute("class", "list-group-item");
  itemDiv.setAttribute("data-bs-toggle", "collapse");
  itemDiv.setAttribute("data-bs-target", `#group_${node.id}`);
  itemDiv.setAttribute("aria-level", `${parentAreaLevel + 1}`);
  itemDiv.setAttribute("objectClass", node.objectClass);
  if (node.prsIndex !== undefined && node.prsIndex !== null && node.prsIndex !== "") itemDiv.setAttribute("data-prs-index", String(node.prsIndex));
  itemDiv.setAttribute("tabindex", "0");
  switch (node.objectClass) {
    case "prsObject":
    case "prsTag":
    case "prsAlert":
    case "prsMethod":
      itemDiv.classList.add(node.objectClass);
  }
  /* drag-and-drop привязка отключена */
  itemDiv.setAttribute("onclick", "clickNode(event);");
  itemDiv.setAttribute("onfocus", "getFocus(event);");

  if ((top) && (parentGroup.children.length > 0)) {
    parentGroup.insertBefore(itemDiv, parentGroup.firstChild);
  } else {
    parentGroup.appendChild(itemDiv);
  };

  if (node.icon) {
    icon = document.createElement("i");
    icon.setAttribute("class", `item-icon ${node.icon}`);
    itemDiv.append(icon)
  }
  var _treeLbl = document.createElement("span");
  _treeLbl.className = "prs-tree-label";
  _treeLbl.textContent = node.text;
  itemDiv.appendChild(_treeLbl);
  if (node.prsDefault) {
    var _badge = document.createElement("span");
    _badge.className = "prs-default-badge";
    _badge.setAttribute("title", "По умолчанию");
    _badge.setAttribute("aria-label", "По умолчанию");
    itemDiv.appendChild(_badge);
  }

  prsEnsureTreeToolbar(itemDiv);
  prsUpdateToolbarVisibility(itemDiv);
  if (typeof prsEnsureChevronPlaceholder === "function") prsEnsureChevronPlaceholder(itemDiv);

  return itemDiv;
}

