function prsAutoLinkTagOrAlertIfNeeded(api, node) {
  const chk = __prsConfiguratorHtmlNode.getElementById("chk-autoLinkTagDefault");
  if (chk && !chk.checked) {
    showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateDataAlert",
      "Создан узел без автопривязки. Выберите хранилище в свойствах тега.", true);
    return;
  }
  const urlDs = window.location.protocol + "//" + window.location.hostname + "/v1/dataStorages/";
  const pQ = new URLSearchParams();
  pQ.append("base", "");
  ["cn", "prsDefault", "prsEntityTypeCode"].forEach(function(a) { pQ.append("attributes", a); });
  fetch(urlDs + "?" + pQ.toString(), { headers: { "Content-type": "application/json" } }).then((response) => {
    if (response.status !== 200) {
      showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", "Ошибка списка хранилищ для привязки.", false);
      return;
    }
    return response.json();
  }).then((data) => {
    if (!data || !data.data || !data.data.length) {
      showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", "Нет хранилищ данных.", false);
      return;
    }
    let defaultDs = data.data.find((d) => prsBoolAttr(d.attributes.prsDefault && d.attributes.prsDefault[0]));
    if (!defaultDs) defaultDs = data.data[0];
    const payload = { id: defaultDs.id };
    if (api === "tags") payload.linkedTags = [{ tagId: node.id }];
    else payload.linkedAlerts = [{ alertId: node.id }];
    fetch(urlDs, {
      method: "PUT",
      body: JSON.stringify(payload),
      headers: new Headers({ "Content-Type": "application/json" })
    }).then((response) => {
      if (response.status !== 202) {
        showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", "Ошибка привязки к хранилищу по умолчанию.", false);
        return;
      }
      if (typeof prsRefreshTagTreeHints === "function") prsRefreshTagTreeHints();
    });
  });
}

