  if (op) params.operation = op;
  const qObj = { tagId: [tagId], params: params };
  if (start) qObj.start = start;
  if (finish) qObj.finish = finish;
  const pData = new URLSearchParams();
  pData.append("tagId", tagId);
  pData.append("params", JSON.stringify(params));
  if (start != null) pData.append("start", start);
  if (finish != null) pData.append("finish", finish);
  const url = window.location.protocol + "//" + window.location.hostname + "/v1/data/?" + pData.toString();
