var newNodeId = null;

addNodeToHierarchy = (api) => {

  url = window.location.protocol + "//" + window.location.hostname + "/v1/" + api + "/";

  parentId = $("div.currentNode")[0].id;

  payload = { attributes: {} };
  if (!((parentId === "objects") || (parentId === "tags") || (parentId === "connectors") || (parentId === "schedules") || (parentId === "dataStorages"))) {
    payload.parentId = parentId;
  }

  fetch(url, {
    method: "POST",
    body: JSON.stringify(payload),
    headers: new Headers({
      'Content-Type': 'application/json'
    })
  }).then((response) => {
    if (response.status !== 201) {
      showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", `Ошибка создания нового узла: ${JSON.stringify(response.json())}`, false);
      return;
    }
    return response.json();
  }).then((data) => {
    if (!data)
      return;
    new_id = data.id;
    const pNew = new URLSearchParams();
    pNew.append("id", new_id);
    pNew.append("attributes", "cn");
    pNew.append("attributes", "objectClass");
    url += "?" + pNew.toString();
    fetch(url, {
      headers: {
        "Content-type": "application/json",
      }
    }).then((response) => {
      if (response.status !== 200) {
        showAlert("div-updateAlert", "div-updateAlertMessage", "i-updateAlert", `Ошибка получения данных по вновь созданному объекту ${new_id}`, false);
        return;
      }
      return response.json();
    }).then((data) => {
      if (!data)
        return;

      divToExtend = __prsConfiguratorHtmlNode.getElementById(parentId);
      node = {
        id: new_id,
        text: data.data[0].attributes.cn[0],
        objectClass: data.data[0].attributes.objectClass[0]
      };
      switch (node.objectClass) {
        case "prsObject":
          node.icon = "fa-solid fa-object-group prsObject";
          break;
        case "prsTag":
          node.icon = "fa-solid fa-tag prsTag";
          break;
        case "prsAlert":
          node.icon = "fa-solid fa-bell prsAlert";
          break;
        case "prsMethod":
          node.icon = "fa-solid fa-file-code prsMethod";
          break;
        case "prsConnector":
          node.icon = "fa-solid fa-link prsConnector";
          break;
        case "prsSchedule":
          node.icon = "fa-solid fa-clock prsSchedule";
          break;
        case "prsDataStorage":
          node.icon = "fa-solid fa-database prsDataStorage";
          break;
      }

      // привяжем тег к хранилищу (авто или вручную — см. переключатель)
      if ((api === "tags") || (api === "alerts")) {
        prsAutoLinkTagOrAlertIfNeeded(api, node);
      }

      var new_node = null;
      if (!($("div.currentNode").attr("aria-expanded"))) {

        var clickEvent = new MouseEvent("click", {
          "view": window,
          "bubbles": true,
          "cancelable": false
        });
        $("div.currentNode").removeClass("currentNode");
        newNodeId = new_id;
        el = __prsConfiguratorHtmlNode.getElementById(parentId);
        el.dispatchEvent(clickEvent);

      } else if (api === "dataStorages") {
        newNodeId = new_id;
        prsLoadDataStoragesUnder(divToExtend, true);
      } else {
        new_node = addNode(divToExtend, node, true);
      }

      if (new_node) {
        var clickEvent2 = new MouseEvent("click", {
          "view": window,
          "bubbles": true,
          "cancelable": false
        });
        new_node.dispatchEvent(clickEvent2);
        new_node.focus();
      }
    })
  });
};

