function prsInitTagDataTableResize() {
  var root = __prsConfiguratorHtmlNode;
  var tbl = root.getElementById("prs-tag-data-table");
  if (!tbl || prsTagDataTableResizeInited) return;
  var thead = tbl.querySelector("thead tr");
  var cols = tbl.querySelectorAll("colgroup col");
  if (!thead || cols.length < 2) return;
  prsTagDataTableResizeInited = true;
  var ths = thead.querySelectorAll("th");
  for (var i = 0; i < ths.length - 1; i++) {
    var th = ths[i];
    var col = cols[i];
    var handle = document.createElement("div");
    handle.className = "prs-tag-data-col-resizer";
    handle.setAttribute("aria-hidden", "true");
    th.style.position = "relative";
    th.appendChild(handle);
    (function (colEl, nextColEl, thEl, nextThEl) {
      handle.addEventListener("mousedown", function (e) {
        e.preventDefault();
        var startX = e.clientX;
        var startW = thEl.offsetWidth;
        var nextW = nextThEl ? nextThEl.offsetWidth : 0;
        function move(e2) {
          var dx = e2.clientX - startX;
          var newW = Math.max(30, startW + dx);
          colEl.style.width = newW + "px";
          if (nextColEl) nextColEl.style.width = Math.max(30, nextW - dx) + "px";
        }
        function up() {
          document.removeEventListener("mousemove", move);
          document.removeEventListener("mouseup", up);
        }
        document.addEventListener("mousemove", move);
        document.addEventListener("mouseup", up);
      });
    })(col, cols[i + 1], th, ths[i + 1]);
  }
}

